final:
module top_module(muxCntrl, In_A, In_B, invalid_out);input muxCntrl;
input [15:0] In_A, In_B; 
output reg [15:0] invalid_out;

always @(muxCntrl, In_A, In_B)
begin

	case (muxCntrl)

		1'b0:
					invalid_out = In_A;
		1'b1:
					invalid_out = In_B;
		default: 
					invalid_out = 16'b0000_0000_0000_0000;
	endcase
end

endmodule
